package tools

import (
	"encoding/json"
	"regexp"
	"strings"
)

// RepairJSON attempts to fix common JSON formatting errors in tool call
// arguments generated by LLMs. This matches openclacky's
// ArgumentsParser with JSON repair logic.
//
// Repairs attempted:
//  1. Trailing commas before } or ]
//  2. Single-quoted strings → double-quoted
//  3. JS-style line comments (// ...)
//  4. Unbalanced brackets (append missing closing brackets)
//
// Returns repaired JSON if any fix produces valid JSON, else original.
func RepairJSON(s string) string {
	if json.Valid([]byte(s)) {
		return s
	}

	// Apply each repair individually; return first valid result
	repairs := []func(string) string{
		repairTrailingCommas,
		repairSingleQuotes,
		repairComments,
		repairUnbalancedBrackets,
		repairUnescapedNewlines,
	}

	for _, r := range repairs {
		fixed := r(s)
		if fixed != s && json.Valid([]byte(fixed)) {
			return fixed
		}
	}

	// Apply all repairs combined
	fixed := s
	for _, r := range repairs {
		fixed = r(fixed)
	}
	if json.Valid([]byte(fixed)) {
		return fixed
	}

	return s
}

// repairTrailingCommas removes commas immediately before } or ].
// Regex-based: matches ",}" and ",]" (with optional whitespace).
var trailingCommaRe = regexp.MustCompile(`,\s*([}\]])`)

func repairTrailingCommas(s string) string {
	return trailingCommaRe.ReplaceAllString(s, "$1")
}

// repairSingleQuotes replaces single-quoted string values with double quotes.
// Only replaces patterns like 'key': 'value' or standalone 'string'.
var singleQuoteValRe = regexp.MustCompile(`:\s*'([^']*)'`)
var singleQuoteKeyRe = regexp.MustCompile(`^\s*'([^']*)'\s*:`)

func repairSingleQuotes(s string) string {
	// Replace single-quoted values: 'value' → "value"
	result := singleQuoteValRe.ReplaceAllString(s, `: "$1"`)
	// Replace single-quoted keys at line start: 'key': → "key":
	result = singleQuoteKeyRe.ReplaceAllString(result, `"$1":`)
	return result
}

// repairComments removes // line comments from JSON.
var lineCommentRe = regexp.MustCompile(`^\s*//.*$`)
var inlineCommentRe = regexp.MustCompile(`\s*//.*$`)

func repairComments(s string) string {
	lines := strings.Split(s, "\n")
	var out []string
	for _, line := range lines {
		// Full-line comments
		if lineCommentRe.MatchString(line) {
			continue
		}
		// Inline comments (only outside strings)
		// Simple heuristic: if line doesn't start with a quote, strip // suffix
		if !strings.Contains(line, `"`) || strings.Index(line, `"`) > strings.Index(line, `//`) {
			line = inlineCommentRe.ReplaceAllString(line, "")
		}
		out = append(out, line)
	}
	return strings.Join(out, "\n")
}

// repairUnbalancedBrackets appends missing closing brackets.
func repairUnbalancedBrackets(s string) string {
	// Count properly (accounting for strings) using a simple parser
	var stack []byte
	inString := false
	for i := 0; i < len(s); i++ {
		if s[i] == '\\' && inString {
			i++ // skip escaped char
			continue
		}
		if s[i] == '"' {
			inString = !inString
			continue
		}
		if inString {
			continue
		}
		if s[i] == '{' || s[i] == '[' {
			stack = append(stack, s[i])
		} else if s[i] == '}' && len(stack) > 0 && stack[len(stack)-1] == '{' {
			stack = stack[:len(stack)-1]
		} else if s[i] == ']' && len(stack) > 0 && stack[len(stack)-1] == '[' {
			stack = stack[:len(stack)-1]
		}
	}

	// Append missing closing brackets
	for i := len(stack) - 1; i >= 0; i-- {
		switch stack[i] {
		case '{':
			s += "}"
		case '[':
			s += "]"
		}
	}
	return s
}

// repairUnescapedNewlines replaces bare newlines inside string values with \\n.
func repairUnescapedNewlines(s string) string {
	var b strings.Builder
	inString := false
	for i := 0; i < len(s); i++ {
		if s[i] == '\\' && inString {
			b.WriteByte(s[i])
			i++
			if i < len(s) {
				b.WriteByte(s[i])
			}
			continue
		}
		if s[i] == '"' {
			inString = !inString
			b.WriteByte(s[i])
			continue
		}
		if inString && s[i] == '\n' {
			b.WriteString("\\n")
			continue
		}
		if inString && s[i] == '\t' {
			b.WriteString("\\t")
			continue
		}
		b.WriteByte(s[i])
	}
	return b.String()
}